#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=5e5+10;
int ch[N][26],len[N],fa[N],lst=1,cnt=1;
inline void ins(int c)
{
	int p=lst,np=lst=++cnt;
	for(;p&&!ch[p][c];p=fa[p])ch[p][c]=np;
	if(!p)fa[np]=1;
	else
	{
		int v=ch[p][c];
		if(len[v]==len[p]+1)fa[np]=v;
		else
		{
			int nv=++cnt;
			fa[nv]=fa[v];len[nv]=len[p]+1;
			memcpy(ch[nv],ch[v],sizeof(ch[v]));
			for(;p&&ch[p][c]==v;p=fa[p])ch[p][c]=nv;
			fa[np]=fa[v]=nv;
		}
	}
}
char s1[N>>1],s2[N>>1];
inline void Solve()
{
	scanf("%s%s",s1,s2);int n=strlen(s1),m=strlen(s2);
	rep(0,n-1,i)ins(s1[i]-'a');
	int p=1,cur=0,ans=0;
	rep(0,m-1,i)
	{
		int c=s2[i]-'a';
		if(!ch[p][c])
		{
			while(p^1&&!ch[p][c])p=fa[p];
			cur=len[p];
		}
		if(ch[p][c])p=ch[p][c],++cur;
		ans=max(ans,cur);
	}
	printf("%d\n",ans);
}
int main()
{
	Solve();
	return 0;
}
